class Solution {
    public int flipLights(int n, int presses) {
        if (n == 0 || presses == 0) return 1;
        if (n == 1) return 2;
        if (n == 2) return presses == 1 ? 3 : 4;
        if (presses == 1) return 4;
        if (presses == 2) return 7;
        return 8;
    }
}
```
